import{_ as a,o as t,c as o,a4 as s}from"./chunks/framework.EG5hAXdg.js";const m=JSON.parse('{"title":"About users","description":"This page gives on overview of user management in HUNT Cloud.","frontmatter":{"title":"About users","category":"HUNT Cloud","permalink":"/administer-science/start-here/users","outline":0,"description":"This page gives on overview of user management in HUNT Cloud."},"headers":[],"relativePath":"administer-science/start-here/users.md","filePath":"administer-science/start-here/users.md"}'),r={name:"administer-science/start-here/users.md"};function n(i,e,l,u,d,c){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="about-user-management" tabindex="-1">About user management <a class="header-anchor" href="#about-user-management" aria-label="Permalink to &quot;About user management&quot;">​</a></h1><p><strong>Over the lifetime of your digital lab, users will come and go. It&#39;s a good investment to understand and optimize the user management process.</strong></p><nav class="table-of-contents"><ul><li><a href="#granting-access-to-new-users">Granting access to new users</a></li><li><a href="#welcoming-new-users-in-your-lab">Welcoming new users in your lab</a></li><li><a href="#offboarding-users">Offboarding users</a></li><li><a href="#read-more">Read more</a></li></ul></nav><h3 id="granting-access-to-new-users" tabindex="-1">Granting access to new users <a class="header-anchor" href="#granting-access-to-new-users" aria-label="Permalink to &quot;Granting access to new users&quot;">​</a></h3><p>You add new users to your lab in our administer science service desk. Each user needs to read their user agreement, and to sign the agreement together with the lab leader or lab coordinator.</p><p>Users will normally get an access link, keys and certificates to your lab a few days after you have submitted the user agreement. We are aware that instant access may sometimes be critical in competitive science, so contact us if one of your users needs instant access to your lab.</p><p>The access link holds a custom guide for how to do the initial access installation. We recommend that each lab user set aside two hours for their first lab access.</p><p>Note that we use the Signal mobile application to forward passphrases and keys to access certificates. It&#39;s good to tell your team to install Signal right away to avoid unnecessary delays.</p><h3 id="welcoming-new-users-in-your-lab" tabindex="-1">Welcoming new users in your lab <a class="header-anchor" href="#welcoming-new-users-in-your-lab" aria-label="Permalink to &quot;Welcoming new users in your lab&quot;">​</a></h3><p>We think one of the best investment you can make in your team is to ensure a good lab onboarding, both technically and scientifically into your projects.</p><p>When you welcome new users into your lab, take the time to show them around as you would in a physical wet lab. This is just like entering a wetlab for the first time. Think of this as going through every cabinet and incubator.</p><p>For example, sit down with your new team members and show them how to run your established workflows and development pipelines, where you store your data, and how to keep your storage areas clean and tidy, and maybe explain how you would like files to be labeled, how to use the different storage volumes, how to ask us for support in Slack and how to request things in our do science service desk, etc.</p><h3 id="offboarding-users" tabindex="-1">Offboarding users <a class="header-anchor" href="#offboarding-users" aria-label="Permalink to &quot;Offboarding users&quot;">​</a></h3><p>You can remove access for lab users whenever you like. In addition, we will automatically remove users that has been inactive for 180 days. We are also here to help ensuring access to data and code from deactivated users inside your lab.</p><p>However, this is a small reminder that it may be good to start to plan how you would like to the offboarding of your lab users to be long before they leave. Remember the old saying: Scientific projects don&#39;t end, they slowly cease to exist when the PhD leaves and no-one has seen the Post Doc for months...</p><p>When that is said, we encourage you to make a small offboarding check-list for users. For example, sit down and go through together what to do about the data and code they have been involved in, make them clean out their local folders, etc.</p><h3 id="read-more" tabindex="-1">Read more <a class="header-anchor" href="#read-more" aria-label="Permalink to &quot;Read more&quot;">​</a></h3><ul><li><a href="/administer-science/service-desk/lab-orders#add-a-new-lab-user">Add a new lab user</a></li></ul>',18)])])}const b=a(r,[["render",n]]);export{m as __pageData,b as default};
